require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/driver_functions.php';require_once ROOT_PATH.'/functions/driver_upload.php';requireAuth();enforceModuleAccess('drivers');$id=(int)($_GET['id']??$_POST['id']??0);$driver=getDriverById($id);if(!$driver){setFlash('danger','Driver not found.');redirect('modules/drivers/index.php');}if($_SERVER['REQUEST_METHOD']==='POST'){if(!verifyCsrfToken((string)($_POST['csrf_token']??''))){setFlash('danger','Invalid form token.');}else{[$ok,$message]=storeDriverDocument($_FILES['document']??[],$id,(string)($_POST['document_type']??'Other'));setFlash($ok?'success':'danger',$message);}redirect('modules/drivers/documents.php?id='.$id);}$statement=getDb()->prepare('SELECT * FROM driver_documents WHERE driver_id=? AND status="Active" ORDER BY created_at DESC');$statement->execute([$id]);$documents=$statement->fetchAll();$pageTitle='Driver documents';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content driver-module"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-heading page-section"><div><h1 class="page-title">Documents · <?=e($driver['full_name'])?></h1><p class="page-subtitle">Secure records with a 5 MB PDF/JPEG/PNG policy.</p></div></section><section class="grid grid-2"><form class="card dashboard-card" method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="id" value="<?=$id?>"><div class="form-group"><label>Document type</label><select name="document_type"><?php foreach(['Driving License','Aadhaar Card','PAN Card','Medical Certificate','Police Verification','Profile Photo'] as $type):?><option><?=e($type)?></option><?php endforeach;?></select></div><div class="form-group"><label>File</label><input type="file" name="document" accept=".pdf,.jpg,.jpeg,.png" required></div><button class="btn btn-primary">Upload document</button></form><article class="card dashboard-card"><h2>Stored documents</h2><ul class="document-list"><?php foreach($documents as $document):?><li><i class="fa fa-file"></i><a href="<?=e(siteUrl($document['file_path']))?>" target="_blank" rel="noopener"><?=e($document['document_type'])?></a><small><?=e(formatDate($document['created_at']))?></small></li><?php endforeach;?><?php if(!$documents):?><li>No documents uploaded.</li><?php endif;?></ul></article></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
